# Math utility functions and base classes

class Drawable:
    @abstract
    def area(self) -> float
    @abstract
    def perimeter(self) -> float

def square(n: int) -> int:
    return n * n

def average(values: list[float]) -> float:
    if len(values) == 0:
        return 0.0
    total: float = 0.0
    for v in values:
        total += v
    return total / float(len(values))

