# Shape classes using math_utils
from math_utils import Drawable, square

class Rectangle(Drawable):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Square(Rectangle):
    side: float

    def __init__(self, side: float):
        super().__init__(side, side)
        self.side = side

    @override
    def area(self) -> float:
        return square(int(self.side))
    @static
    UNIT: Square
    @static def get_unit() -> Square:
        return Square(1.0)

# Initialize static field
Square.UNIT = Square(1.0)
